#include <stdio.h>
#include <stdlib.h>
#include <math.h>
#include <omp.h>

#ifndef BLOCK_SIZE
#define BLOCK_SIZE 16
#endif

#define MIN(i,j) ((i)<(j) ? (i) : (j))

void lud_diagonal(float *m, int matrix_dim, int offset) {
    int i, j, tx;
    float shadow[BLOCK_SIZE * BLOCK_SIZE];
    int array_offset = offset * matrix_dim + offset;

    // Load diagonal block into shadow (parallelized over tx)
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_offset = array_offset + tx;
        for (i = 0; i < BLOCK_SIZE; i++) {
            shadow[i * BLOCK_SIZE + tx] = m[local_offset];
            local_offset += matrix_dim;
        }
    }

    // LUD decomposition on the diagonal block
    for (i = 0; i < BLOCK_SIZE - 1; i++) {
        #pragma omp parallel for
        for (tx = i + 1; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i; j++) {
                sum += shadow[tx * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + i];
            }
            shadow[tx * BLOCK_SIZE + i] -= sum;
            shadow[tx * BLOCK_SIZE + i] /= shadow[i * BLOCK_SIZE + i];
        }

        #pragma omp parallel for
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            float sum = 0.0f;
            for (j = 0; j < i + 1; j++) {
                sum += shadow[(i + 1) * BLOCK_SIZE + j] * shadow[j * BLOCK_SIZE + tx];
            }
            shadow[(i + 1) * BLOCK_SIZE + tx] -= sum;
        }
    }

    // Write back the lower part of the diagonal block (rows 1 to BLOCK_SIZE-1)
    array_offset = (offset + 1) * matrix_dim + offset;
    #pragma omp parallel for
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int local_offset = array_offset + tx;
        for (i = 1; i < BLOCK_SIZE; i++) {
            m[local_offset] = shadow[i * BLOCK_SIZE + tx];
            local_offset += matrix_dim;
        }
    }
}

void lud_perimeter(float *m, int matrix_dim, int offset, int num_blocks) {
    int i, j, bx, tx;
    float dia[BLOCK_SIZE * BLOCK_SIZE];
    float peri_row[BLOCK_SIZE * BLOCK_SIZE];
    float peri_col[BLOCK_SIZE * BLOCK_SIZE];

    #pragma omp parallel for private(i, j, bx, tx)
    for (bx = 0; bx < num_blocks; bx++) {
        // Determine thread assignment for this block
        // In OpenCL, 2*BLOCK_SIZE threads were used per block group.
        // We simulate this by having each thread handle a specific role or iterating.
        // To match the parallelism structure:
        // Threads 0..BLOCK_SIZE-1 handle row operations
        // Threads BLOCK_SIZE..2*BLOCK_SIZE-1 handle col operations

        // Since we are in a standard parallel loop, we iterate over the logical threads
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            int idx;
            int array_offset;

            if (tx < BLOCK_SIZE) {
                idx = tx;
                // Load diagonal (first half)
                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE / 2; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                // Load perimeter row
                array_offset = offset * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_row[i * BLOCK_SIZE + idx] = m[array_offset + (bx + 1) * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            } else {
                idx = tx - BLOCK_SIZE;
                // Load diagonal (second half)
                array_offset = (offset + BLOCK_SIZE / 2) * matrix_dim + offset;
                for (i = BLOCK_SIZE / 2; i < BLOCK_SIZE; i++) {
                    dia[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }

                // Load perimeter col
                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    peri_col[i * BLOCK_SIZE + idx] = m[array_offset + idx];
                    array_offset += matrix_dim;
                }
            }
        }

        // Barrier implied by sequential execution within the block scope in OpenMP if we structure it right, 
        // but here we just proceed. The original code had barriers between load and compute.
        // In OpenMP, since we are inside a parallel region but the logic is sequential per block group,
        // we need to ensure all loads are done before computes. 
        // However, the original kernel structure implies all threads in the group participate.
        // We will split the load and compute phases.

        // Compute phase
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            int idx;
            if (tx < BLOCK_SIZE) {
                idx = tx;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    float sum = 0.0f;
                    for (j = 0; j < i; j++) {
                        sum += dia[i * BLOCK_SIZE + j] * peri_row[j * BLOCK_SIZE + idx];
                    }
                    peri_row[i * BLOCK_SIZE + idx] -= sum;
                }
            } else {
                idx = tx - BLOCK_SIZE;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    float sum = 0.0f;
                    for (j = 0; j < i; j++) {
                        sum += peri_col[idx * BLOCK_SIZE + j] * dia[j * BLOCK_SIZE + i];
                    }
                    peri_col[idx * BLOCK_SIZE + i] -= sum;
                    peri_col[idx * BLOCK_SIZE + i] /= dia[i * BLOCK_SIZE + i];
                }
            }
        }

        // Write back phase
        for (tx = 0; tx < 2 * BLOCK_SIZE; tx++) {
            int idx;
            int array_offset;
            if (tx < BLOCK_SIZE) {
                idx = tx;
                array_offset = (offset + 1) * matrix_dim + offset;
                for (i = 1; i < BLOCK_SIZE; i++) {
                    m[array_offset + (bx + 1) * BLOCK_SIZE + idx] = peri_row[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            } else {
                idx = tx - BLOCK_SIZE;
                array_offset = (offset + (bx + 1) * BLOCK_SIZE) * matrix_dim + offset;
                for (i = 0; i < BLOCK_SIZE; i++) {
                    m[array_offset + idx] = peri_col[i * BLOCK_SIZE + idx];
                    array_offset += matrix_dim;
                }
            }
        }
    }
}

void lud_internal(float *m, int matrix_dim, int offset, int num_blocks) {
    int bx, by, tx, ty, i;

    #pragma omp parallel for private(bx, by, tx, ty, i)
    for (by = 0; by < num_blocks; by++) {
        for (bx = 0; bx < num_blocks; bx++) {
            int global_row_id = offset + (by + 1) * BLOCK_SIZE;
            int global_col_id = offset + (bx + 1) * BLOCK_SIZE;

            float peri_row[BLOCK_SIZE * BLOCK_SIZE];
            float peri_col[BLOCK_SIZE * BLOCK_SIZE];
            float sum;

            // Load
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    peri_row[ty * BLOCK_SIZE + tx] = m[(offset + ty) * matrix_dim + global_col_id + tx];
                    peri_col[ty * BLOCK_SIZE + tx] = m[(global_row_id + ty) * matrix_dim + offset + tx];
                }
            }

            // Compute
            for (ty = 0; ty < BLOCK_SIZE; ty++) {
                for (tx = 0; tx < BLOCK_SIZE; tx++) {
                    sum = 0.0f;
                    for (i = 0; i < BLOCK_SIZE; i++) {
                        sum += peri_col[ty * BLOCK_SIZE + i] * peri_row[i * BLOCK_SIZE + tx];
                    }
                    m[(global_row_id + ty) * matrix_dim + global_col_id + tx] -= sum;
                }
            }
        }
    }
}

void lud_omp(float *m, int matrix_dim) {
    int i;
    int num_blocks = (matrix_dim / BLOCK_SIZE) - 1;

    for (i = 0; i < matrix_dim - BLOCK_SIZE; i += BLOCK_SIZE) {
        int offset = i;

        // 1. Diagonal
        lud_diagonal(m, matrix_dim, offset);

        // 2. Perimeter
        if (num_blocks > 0) {
            lud_perimeter(m, matrix_dim, offset, num_blocks);
        }

        // 3. Internal
        if (num_blocks > 0) {
            lud_internal(m, matrix_dim, offset, num_blocks);
        }

        num_blocks--;
    }

    // Final diagonal step for the last block
    lud_diagonal(m, matrix_dim, matrix_dim - BLOCK_SIZE);
}
